INSERT INTO `field_images` (`pages_id`, `data`, `sort`, `description`, `modified`, `created`, `filedata`, `filesize`, `created_users_id`, `modified_users_id`, `width`, `height`, `ratio`) VALUES('2147', 'lernen_1.jpeg', '0', '[\"\"]', '2026-03-22 15:06:40', '2026-03-22 15:02:25', '{\"uploadName\":\"Lernen 1.jpeg\",\"_136\":\"Permakultur-Ethik auf einem Blatt. Nahaufnahme einer Hand mit Schmuck und Kugelschreiber, tr\\u00e4gt etwas ein im Feld \\\"Sorge f\\u00fcr die Menschen\\\"\",\"_137\":\"\",\"_149\":\"Je intensiver wir uns damit befassen, desto mehr verwebt sich die ethische Basis in dein Leben. Ganz einfach!\",\"_134\":\"2024\",\"_144\":\"Carolin Herrlich\",\"_138\":\"http:\\/\\/www.herrliche-permakultur.de\",\"_125\":[1120],\"ix\":\"134_2024 125_1120\"}', '559596', '41', '41', '2016', '1512', '1.33');
