INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1', 'Herrliche Permakultur ist die Webseite von Carolin Herrlich. Sie gestaltet soziale RÃ¤ume, Alltag und GÃ¤rten mit sozialer und zyklischer Permakultur.');
