INSERT INTO `field_meta_description` (`pages_id`, `data`) VALUES('1223', 'Die Ethik der Permakultur bildet mit der Sorge fÃ¼r die Erde, der Sorge fÃ¼r die Menschen und gerechtes Teilen die Grundlage fÃ¼r nachhaltiges Handeln.');
