INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '21', '1', '1023:<p>O</p>', '1023:<p>31.3. FrÃ¼hling - 6 Uhr Sonnenaufgang - GrÃ¤ser und Knospen beginnen zu sprieÃen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '22', '2', '1023:<p>SO</p>', '1023:<p>1.5. FrÃ¼hsommer - 9 Uhr Vormittag - Wachstum zu Ã¼ppigem Blattwerk</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '23', '3', '1023:<p>S</p>', '1023:<p>22.6. Sommeranfang - 12 Uhr Mittag - Ã¼ppige BlÃ¼ten und viele Insekten</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '24', '4', '1023:<p>SW</p>', '1023:<p>1.8. SpÃ¤tsommer - 15 Uhr Siesta - Zeit des Reifens und der FÃ¼lle</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '25', '5', '1023:<p>W</p>', '1023:<p>23.9. Herbstanfang - 18 Uhr Feierabend - reife FrÃ¼chte und verholzende Stengel</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1726', '26', '6', '1023:<p>NW</p>', '1023:<p>31.10. SpÃ¤therbst - 21 Uhr DÃ¤mmerung - welke BlÃ¤tter, Samen fallen auf den Boden</p>');
