INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '28', '0', '1023:<p>Ziel</p>', '1023:<p>Die Mitarbeiter des Palliativteams Ã¤uÃern ihre WÃ¼nsche und BedÃ¼rfnisse hinsichtlich eines Team-Abschiedsrituals fÃ¼r Verstorbene Patienten. Wir lernen uns besser kennen und bilden eine gemeinsame Kultur aus.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '29', '1', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>Alpha-BADUZ</p>\n\n<p>People Care: bei der Begleitung von nicht mehr heilbaren Menschen ohne professionelle psychologische UnterstÃ¼tzung brauchen wir Rituale um zu verarbeiten.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '30', '2', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Klares Vorgehen bei der Vorbereitung und dem Setting dass ich schon sehr viel von der neuen Kulturschaffung umsetze. Ich sah es bei der Reflexion mit den sozialen Looby-Prinzipien. Ein Feldversuch um neue Kultur zu schaffen-angelegt auf Basis der Permakulturwerkzeuge. Ich habe damit nicht nur mit der Gruppe die Antwort auf eine Frage gesucht, sondern im tieferen Sinne eine gemeinsame neue Kultur inspiriert, die sich entwickeln kann.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1501', '31', '3', '1023:<p>AHAÂ´s und Gestaltung</p>', '1023:<p>Systemisches konsensieren und Moderation in den 8 schilden hat wunderbar funktioniert wir kamen gemeinsam ins TrÃ¤umen und es wurde deutlich welchen Konsens die Gruppe findet Punkt aha alle Kollegen haben sich gegenseitig gehÃ¶rt in ihren BedÃ¼rfnissen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '32', '0', '1023:<p>Ziel</p>', '1023:<p>Planung eines Alters- und rollstuhlgerechten Schrebergarten mit viel Altbestand und Material fÃ¼r zwei Generationen. Ein bunter, strukturreicher Schrebergarten fÃ¼r IndividualitÃ¤t, Vielfalt und Gemeinsamkeit.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '33', '1', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>OBREDIMET und</p>\n\n<p>People care-nur gemeinsam kÃ¶nnen wir stabile, resiliente Systeme kreieren!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '34', '2', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Dreh- und Angelpunkt war der Besuch und das GesprÃ¤ch mit den Menschen vor Ort. Im Design habe ich SchwÃ¤chen zu stÃ¤rken verwandelt! Viel verstreutes Material wird zu Struktur und gemeinsamen Projekten. Zudem hat mich das OBREDIMET in einer Ãbersetzung von Judith Barthel diesmal differenziert geleitet. Ich habe auch auf mich selbst geachtet!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1482', '35', '3', '1023:<p>AHAÂ´s und Gestaltung</p>', '1023:<p>Mit mÃ¶glichst wenig Eintrag und Aufwand einen pflegeleichten einfachen Garten gestalten. Ich habe mit dem gearbeitet was da war! Kein Schnickschnack oder sehr aufwendige Projekte. Mit den klaren Methoden der Permakultur habe ich einen umsetzbares, schÃ¶nes und funktionales Design kreiert. Aha\'s: zwei Umsetzungsplanungen: eine zum Diskutieren, eine zum TrÃ¤umen. Ein erster Entwurf funktioniert super als Diskussionsgrundlage.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '36', '0', '1023:<p>Prozessmodell</p>', '1023:<p>Phasen und <em>AnwendungsmÃ¶glichkeiten</em></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '37', '1', '1023:<p>BADUZ</p>', '1023:<p>Beobachten â Analyse â Design â Umsetzung- Zelebrieren</p>\n\n<p><em>Unbegrenzt, auch gut fÃ¼r Mini-Designs</em></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '38', '2', '1023:<p>OVBREDIMET</p>', '1023:<p>Observation â Vision â Boundaries and resources â Recording of site â Examination and analysis â Design strategies chosen â Implementation strategie - Maintenance requirement â Evaluation of Results â Tweaking for improvemenet</p>\n\n<p><em>Optimal im grÃ¼nen Permakultur-Bereich</em></p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1809', '39', '3', '1023:<p>DesignWeb<sup class=\"footnote\"><span style=\"background-color:#fcc000;font-size:12px;\">1</span></sup></p>', '1023:<p>Wachstumsphase â Entdeckungsphase â Produktionsphase - Reflexionsphase</p>\n\n<p><em>Geeignet fÃ¼r groÃe Projektideen und soziale Designs und Gemeinschaftsprojekte, eher intuitiv</em></p>');
