INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '41', '1', '1023:<p style=\"margin-left:48px;\">Ich verstehe die Welt nicht...</p>', '1023:<p>...Bedingungen und Wechselbeziehungen neu begreifen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '42', '2', '1023:<p style=\"margin-left:48px;\">Ãberforderung...</p>', '1023:<p>...natÃ¼rlich ZusammenhÃ¤nge begreifen und den Blick fÃ¼r die kleinen Wunder der Welt schÃ¤rfen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1812', '43', '3', '1023:<p style=\"margin-left:48px;\">Wo fange ich an, was kann ich tun?....</p>', '1023:<p>....spielerisch Ideen generieren und klare nÃ¤chste Schritte verfolgen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1834', '44', '0', '1023:<p>1. Jahr</p>', '1023:<p>Sonnenblume pflanzen = Standortthese prÃ¼fen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1834', '45', '1', '1023:<p>2. Jahr</p>', '1023:<p>Biokompost an der Pflanzstelle vergraben. Im Herbst Stecklinge fÃ¼r die OLG schneiden, z.B. Johannisbeeren, Muskatellersalbei oder Fette Henne. Recherche zu regionale, evtl. seltenen alten Obstbaumsorten.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1834', '46', '2', '1023:<p>3. Jahr</p>', '1023:<p>im FrÃ¼hjahr die Baumscheibe von Gras befreien und eine GrÃ¼ndÃ¼ngung als Vorbereitung anlegen. Baumschule des Vertrauens finden. Im Herbst den Baum wurzelnackt einpflanzen und die Obstbaumgilde anlegen. Mulchen und freuen!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1846', '47', '0', '1023:<p>Baumstamm, Blitze , Blattrosette bei zweijÃ¤hrigen Stauden...</p>', '1023:<p>Vision einer Gruppe, detailliertes Zone 1- Design, KÃ¼che im Haus als Lebensmittelpunkt</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1848', '49', '0', '1023:<p>Wasserkreislauf,</p>\n\n<p>ErnÃ¤hrungskreislauf,</p>\n\n<p>positive und negative RÃ¼ckkopplung im Ãkosystem</p>', '1023:<p>Cradle 2 Cradle,</p>\n\n<p>Kompostierung,</p>\n\n<p>Feedbackschleife</p>');
