INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1868', '52', '2', '1023:<p>Zuviele GartengerÃ¤te</p>', '1023:<p>sozial wertvolle Ausleihe fÃ¼r Nachbarn</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('1936', '53', '0', '1023:<p>Entwicklung einer FlÃ¤che hin zu Wald,</p>\n\n<p>Baumwachstum,</p>\n\n<p>Moosentwicklung</p>', '1023:<p>LebensverÃ¤nderungen wie âÃ¤lter werdenâ mit einplanen,</p>\n\n<p>grÃ¶Ãer werdende BÃ¤ume mit den Jahren nutzen (Obstbaumgilde),</p>\n\n<p>lebendige Bauten mit Weiden</p>');
