INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2067', '62', '0', '1023:<p>Aktives zuhÃ¶ren</p>', '1023:<p>Mit dem Bewusstsein des Vier-Ohren-Modells<sup class=\"footnote\">1</sup>. Manchmal genÃ¼gt es, einfach nur zuhÃ¶ren ohne sofort darauf reagieren zu mÃ¼ssen. Ein schÃ¶nes Beispiel dafÃ¼r ist ein Redekreis<sup class=\"footnote\">2</sup>, der viele Funktionen vereint und Tiefe in der Zwischenmenschlichkeit schaffen kann. Eine WertschÃ¤tzende GesprÃ¤chsfÃ¼hrung ist ein wichtiger Teil von Inklusion!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2067', '63', '1', '1023:<p>Konsens-Prinzip</p>', '1023:<p>Echtes zuhÃ¶ren, klar Ã¤uÃern und anwenden. Systemisches Schnell-Konsensieren fÃ¼r alltÃ¤gliche Situationen, beispielsweise die Abendplanung!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2067', '64', '2', '1023:<p>Verantwortung fÃ¼r mich Ã¼bernehmen</p>', '1023:<p>Mithilfe der BedÃ¼rfnissprache:. Bedeutet nicht mein BedÃ¼rfnis bei jemandem abladen, sondern mit Klarheit zu Ã¤uÃern: âich bin mÃ¼de, hungrig, durstig,â¦â. FÃ¼r mich selbst Verantwortung zu Ã¼bernehmen und sorgen zu kÃ¶nnen, um dann auch fÃ¼r meine Umgebung sorgen zu kÃ¶nnen.</p>');
