INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2086', '66', '1', '1023:<p>Flexible StrukturrÃ¤ume:</p>', '1023:<p>Wie Veranstaltungen oder Meetings plane ich oft zyklisch mit den acht Schilden. Das fÃ¼hlt sich kongruent und schÃ¶n an. Probier es auch aus!</p>');
