INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '68', '0', '1023:<p>\"Ich habe zwei Stunden Zeit pro Woche und mÃ¶chte hauptsÃ¤chlich frisch ernten und kochen.\"</p>', '1023:<p>Statt eines intensiven GemÃ¼sebeets habe ich mich fÃ¼r drei ObstbÃ¤ume mit KrÃ¤uterbaumscheiben und DauergemÃ¼sebeete entschieden. Meine persÃ¶nlichen Highlights: Salat mit essbaren BlÃ¼ten&amp; WildkrÃ¤utern und die Apfelernte im Herbst!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '69', '1', '1023:<p>\"Ich wÃ¼nsche mir einen harmonischen Ziergarten der auch nutzbar ist und mich erfreut!\"</p>', '1023:<p>Meine Bauerngarten-Stauden-Rabatte sind ergÃ¤nzt mit DauergemÃ¼se wie Mangold der schÃ¶n fÃ¼r Insekten blÃ¼ht. Unterschiedlichste BlÃ¼ten setzen die einzelnen GartenplÃ¤tze Ã¼bers ganze Jahr verteilt in Szene und sind Insektenmagnete! In einem eher sonnigen und mageren Beet habe ich heimische Magerpflanzen kombiniert mit Holzkunst-Elementen die sich nach und nach zersetzen und Heimat werden fÃ¼r unzÃ¤hlige kleine, nÃ¼tzliche Garten-Mitbewohner</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2096', '70', '2', '1023:<p>\"Der Garten soll fÃ¼r meine Familie ein Ort der Ruhe, des Spielens und Lernens mit der Natur sein.\"</p>', '1023:<p>Wir haben einen Grillplatz mit offenem Pflaster, Mini-bete fÃ¼r die Kinder, Erdbeer-naschsÃ¤ume an den Wegen und Verstecke, wie der Weidentunnel. Immer parat: Lupe, BÃ¼cher und eine Pflanzenpresse.</p>');
