INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '81', '3', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Ein ganzes Design Wochenende organisiert mit allen Beteiligten, um gemeinsam ein Design fÃ¼r den Acker zu entwerfen. Schritt fÃ¼r Schritt sind wir durch den Prozess gegangen, was auch beinhaltet die BedÃ¼rfnisse und Begrenzung der Gruppe zu finden.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '82', '4', '1023:<p>AHAÂ´s und Gestaltung</p>', '1023:<p>Das Ressourcen Brainstorming war hat sich gegenseitig potenziert. Am Ende des Designums hatten wir ein klares Konzept und klare weitere Zuordnung der weiteren Planung und AGs im Team. Und besonders viel SpaÃ bei der Maximalplanung fÃ¼r WÃ¼hlmÃ¤use.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2103', '83', '5', '1023:<p>Fazit</p>', '1023:<p>Fazit ein schÃ¶ner und intensiver Prozess bei dem ich gefÃ¼hlt in zwei Wochen so viel Ã¼ber Permakultur Design gelernt und gelebt habe wie in einem Jahr. Das war mein erstes grÃ¶Ãeres Projekt aus dem Permakultur Basisjahr 2020.</p>');
