INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '85', '1', '1023:<p>Ziel</p>', '1023:<p>Permakultur-Blitzaktion als Projektgruppe umzusetzen, etwas Dauerhaftes anzulegen und die Artenvielfalt zu unterstÃ¼tzen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '86', '2', '1023:<p>Prozessmodell und ethischer Schwerpunkt</p>', '1023:<p>BADUZ</p>\n\n<p>Ethischer Schwerpunkt: sozial. Bereits die Umsetzung war stark GruppenprÃ¤gend, ein geeminsames Herzensprojekt umzusetzen. ZusÃ¤tzlich sollen Nachbarn inspiriert werden!</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '87', '3', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Ich vor allem planerisch. Habe immer wieder ganzheitlich versucht, die Parteien und AnsprÃ¼che unter einen im Kontext sinnvollen Hut zu bringen und âetwas draus zu machenâ. Vor allem die Aufarbeitung und Projektdokumentation im Nachhinein bringt mir sehr viel. Wunderbar unterstÃ¼tzt hat mich das Prozessmodell BADUZ mit den klaren Anhaltspunkten.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2107', '88', '4', '1023:<p>AHAÂ´s und Gestaltung</p>', '1023:<ul>\n	<li>\n	<p>Klar fragen: gibt es noch Unklarheiten? Was ist der Nordstern?</p>\n	</li>\n	<li>\n	<p>Heimische Stauden und ihre AnsprÃ¼che</p>\n	</li>\n	<li>\n	<p>Wie baue ich ein Up-Cycling Insektenhotel</p>\n	</li>\n	<li>\n	<p>Koordination der Umsetzung von bis zu 10 Menschen. Das GespÃ¼r fÃ¼r eine Pause.</p>\n	</li>\n	<li>\n	<p>Beim Zeichnen: Klare Anforderung an den Plan, fÃ¼r wen, welche Zeit und was genau soll wie abstrakt dargestellt werden? Immer einnorden zur besseren Ãbersichtlichkeit.</p>\n	</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '89', '0', '1023:<p>Was?</p>', '1023:<p>Ein ewiges Gartenhandbuch fÃ¼r das ToGenJi-Projekt. https://www.permakultur.de/ort/togenji-projekt/</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '90', '1', '1023:<p>Ziel</p>', '1023:<p>Ein einfaches Tool fÃ¼r die Planung der Arbeit im Intensiven Selbstversorger-GemÃ¼segarten des ToGenJiÂ´s. <em>FÃ¼r Wen:</em> hauptsÃ¤chlich fÃ¼r Bufdis, Praktikanten und GÃ¤ste die lÃ¤nger bleiben. <em>HauptqualitÃ¤ten:</em> einfach, praktikabel, anschaulich</p>');
