INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '92', '3', '1023:<p>Wie habe ich permakulturell gearbeitet?</p>', '1023:<p>Einbeziehen der aktuellen Nutzer und neuen Erfahrungen sowie schon vorhandenen Tools, Entwicklung des Produktidee aus einer offenen Evaluationsrunde. Ich merke immer mehr, wie meine QualitÃ¤t des âSichtbar machensâ mehr und mehr Gestalt annimmt und schneller, flÃ¼ssiger, besser wird! Dass meine Fotos der letzten 3 Jahre hier eingeflossen sind (inkl. Essensbilder) empfinde ich als Ganzheitlich.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2114', '93', '4', '1023:<p>AHAÂ´s und Gestaltung</p>', '1023:<ul>\n	<li>\n	<p>Ich arbeite gerne und viel mit Listen, Tabelle. Ich strebe nach Ãbersichtlichkeit!</p>\n	</li>\n	<li>\n	<p>Ãbersichtlicher Garten 2021, 2022 gefÃ¼hrt und dann schnelle verwilderung: Das System braucht Pflege. Und einen Notfallplan ð</p>\n	</li>\n	<li>\n	<p>SchÃ¶ne Zusammenarbeit mit anderen: sie machen etwas aus der Basis, es entwickelt sich!!!!</p>\n	</li>\n	<li>\n	<p>Wichtig: Andere mit ins Boot holen, das initiale âEvaluationstreffenâ mit offenem Ausgang war Samen legen: Es gibt konkrete weitere Projekte und Ideen zur weiteren Verstetigung vom ToGenJi-Projekt (mehrere mÃ¶gliche Ziele und eine Sukzessionsplanung von Ideen). Klare Rollenverteilungen, einige klare nÃ¤chste Schritte.</p>\n	</li>\n	<li>\n	<p>FÃ¼r mich lang ersehntes ârund machenâ der Zeit hier, weil jetzt klare Rolle als âGarteberaterInâ (kann kontaktiert werden und frage aktiv nach, wenn ich vor Ort bin). <em>(EDIT: Das wird gerade nicht benÃ¶tigt, ich stehe zur VerfÃ¼gung)</em> Zudem erstelle ich weiter die GemÃ¼segartenplanungen auf Basis der Matrix die ich entwickelt habe. KrÃ¶nung und damit auch diese Dokumentation: Das Gartenbooklet</p>\n	</li>\n	<li>\n	<p>Zonierung in Kombi mit SWOC-Analyse und Ãkosystemkriterien an geeigneter Stelle anwenden</p>\n	</li>\n</ul>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '94', '0', '1023:<p>1. Beobachte und interagiere</p>', '1023:<p>Prinzip bei der Standortwahl von Pflanzen anwenden, Nachbarn helfen.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '95', '1', '1023:<p>2. Sammle und speichere Energie</p>', '1023:<p>Regenwasser leicht erhÃ¶ht auffangen zur passiven BewÃ¤sserung, Aufschreiben von motivierenden Gedanken.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '96', '2', '1023:<p>3. Erziele eine Ernte</p>', '1023:<p>Nahrungsmittel, Naturbeobachtung, Wissensaustausch.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '97', '3', '1023:<p>4. Lass die Natur regulieren und lerne aus Feedback</p>', '1023:<p>Ãkosysteme regulieren sich selbst und sind sehr produktiv. Klassiker ist den biologischen Pflanzenschutz durch Mischkultur und NÃ¼tzlinge zu fÃ¶rdern.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '98', '4', '1023:<p>5. Nutze und schÃ¤tze erneuerbare Ressourcen und Dienstleistungen</p>', '1023:<p>Handarbeit, Wind und Sonne, ErdwÃ¤rme, Regenwurmer als MitgÃ¤rtner und Bodenaufbauer</p>');
