INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '100', '6', '1023:<p>7. Gestalte vom Muster zum Detail</p>', '1023:<p>Grundstruktur planen, dann den konkreten Inhalt.</p>\n\n<p>Muster: Wo ist die Betreuung des intensiven Nutzgartens einfach und wieviel BeetflÃ¤che brauche ich?</p>\n\n<p>Detail: Beetaufbau und Pflanzen</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '101', '7', '1023:<p>8. Integriere mehr, als Du trennst</p>', '1023:<p>Eine Laube kann genutzt werden zum aufbewahren, DachflÃ¤chenwasser sammeln und Anbau an der SÃ¼dseite. Im sozialen Bereich ist wichtig z.b barrierearm und integrativ zu gestalten.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '102', '8', '1023:<p>9. Nutze kleine und langsame LÃ¶sungen</p>', '1023:<p>Alles braucht seine Zeit und gesundes Wachstum auch! Mit kleinen VerÃ¤nderungen kÃ¶nnen wir den Ãberblick behalten, Funktionsweisen begreifen und SchÃ¤den verhindern. Z.b. langsames Gestalten des Gartens in Jahresetappen, zuerst GehÃ¶lze und ein paar DauergemÃ¼sebeete anlegen. Danach Baumscheiben, GemÃ¼sebeete und ein Kompostsystem etablieren.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '103', '9', '1023:<p>10. Nutze und schÃ¤tze Vielfalt</p>', '1023:<p>Essbare Landschaften sind reizvoll, weil die DiversitÃ¤t Ã¼bers Jahr auf dem Teller einladend ist und die Gestaltung oft dem 7-schichtigen Waldgartenprinzip folgt.</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '104', '10', '1023:<p>11. Nutze Randzonen, und schÃ¤tze das Marginale</p>', '1023:<p>Artenreiche SÃ¤ume schaffen, wie: GewÃ¤sserrÃ¤nder, Mauerkronen und-fÃ¼Ãe gestalten, Beetbegrenzung als NÃ¼tzlingsaufenthaltsorte. Und Randzonen wie den Wegesrand als NaschsÃ¤ume nutzen! :)</p>');
INSERT INTO `field_table` (`pages_id`, `data`, `sort`, `title`, `value`) VALUES('2155', '105', '11', '1023:<p>12. Reagiere kreativ auf VerÃ¤nderungen</p>', '1023:<p>In der VerÃ¤nderung die Chance auf Verbesserung sehen: Klimawandel = Pflanzenwandel, spezielle Nischen.</p>\n\n<p>Oder ein umgestÃ¼rzter, alter Obstbaum wird zum absoluten Highlight-Habitat im Garten.</p>');
