INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1742', '<h6>Individuelle Kurzberatung â fokussiert, persÃ¶nlich und wirkungsvoll.</h6>\n\n<p>Diese 1:1-Onlineberatung eignet sich besonders, wenn du:</p>\n\n<ul>\n	<li>\n	<p>konkrete Impulse fÃ¼r deinen Garten, dein Projekt oder andere LebensrÃ¤ume suchst</p>\n	</li>\n	<li>\n	<p>eine klare, strukturierte Beratung mÃ¶chtest</p>\n	</li>\n	<li>\n	<p>Ã¼ber das GesprÃ¤ch hinaus Anregungen fÃ¼r die nÃ¤chsten Schritte brauchst</p>\n	</li>\n</ul>\n\n<p>Vor unserem Termin erhÃ¤ltst du einen detaillierten Fragebogen. So kann ich mich gezielt auf deine Situation vorbereiten und unsere gemeinsame Zeit optimal nutzen.</p>\n\n<h6>Ablauf</h6>\n\n<ul>\n	<li>\n	<p>Fragebogen &amp; Terminvereinbarung</p>\n	</li>\n	<li>\n	<p>1 Stunde persÃ¶nliches Online-BeratungsgesprÃ¤ch</p>\n	</li>\n	<li>\n	<p>weiterfÃ¼hrende Impulse &amp; Materialien</p>\n	</li>\n	<li>\n	<p>zusÃ¤tzlich: 1 Ticket fÃ¼r eine Permakultur-Sprechstunde</p>\n	</li>\n</ul>\n\n<h6>Rahmen</h6>\n\n<p>ð§­ online | 1:1<br />\nâ± Dauer der Beratung: 1 Stunde<br />\nð Preis: 150 â¬<br />\nð inkl. 1 Ticket zur Permakultur-Sprechstunde</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1743', '<h6>Permakultur-Sprechstunde â offen fÃ¼r dich &amp; deine Fragen.</h6>\n\n<p>Du stehst vor einer Herausforderung in deinem Garten, Projekt oder Lebensraum? Permakultur denkt ganzheitlich â und genau dafÃ¼r ist diese Sprechstunde da.</p>\n\n<p>In der monatlichen Online-Sprechstunde treffen wir uns in einer kleinen Gruppe. Wir beginnen bewusst im Redekreis, um anzukommen und einen offenen, wertschÃ¤tzenden Raum zu schaffen. AnschlieÃend beantworte ich eure Fragen aus der Perspektive der Permakultur â praxisnah, systemisch und lÃ¶sungsorientiert.</p>\n\n<p>Wenn du mÃ¶chtest, kannst du mir deine Frage bereits bei der Anmeldung schicken, damit ich mich gezielt vorbereiten kann. Je nach Zeit gibt es zusÃ¤tzlich einen kurzen Mini-Input zur Inspiration.</p>\n\n<h6>Ablauf</h6>\n\n<ul>\n	<li>ca. 30 Min. Ankommen &amp; Redekreis</li>\n	<li>ca. 45 Min. offene Fragerunde</li>\n	<li>ggf. Austausch oder Mini-Input</li>\n</ul>\n\n<h6>Rahmen</h6>\n\n<p>ð§­ online | Gruppen-Call | 1Ã im Monat<br />\nð max. 15 Teilnehmende<br />\nâ± Dauer: 1,5 Stunden<br />\nð Preis: 25 â¬</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1748', '<p><strong>Offene Online-Sprechstunde in einer Gruppe fÃ¼r deine Permakultur-Fragen.</strong><br />\nGemeinsam ankommen, austauschen und konkrete Impulse mitnehmen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1749', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1753', '<p>Du mÃ¶chtest aufbauend sein und zukunftsfÃ¤hig handeln. Was findest Du sinnvoll und mÃ¶chtest es unterstÃ¼tzen?</p>\n\n<p>Wenn Du es noch nicht weiÃt: probiere die Ikegai-Methode.</p>\n\n<p>Es gibt abertausende und noch mehr fantastische Ideen, Initiativen und kreative Menschen.</p>\n\n<p>Deine Startfrage: Wo erlebst Du Dich wirkungsvoll und gestaltend? Circle of Condern.</p>\n\n<p>Im Folgenden findest Du ein paar wenige von unzÃ¤hligen, groÃartigen und wirkungsvolllen Beispielen:</p>\n\n<p><strong>1 </strong><strong>Dein direktes Umfeld</strong> (Zeitwohlstand, nachhaltiges Arbeiten, naturnaher und insektenfreundlicher Garten, pro-igel.de, Saatgut und ErnteÃ¼berschÃ¼sse teilen, Nachbarschaftsfest organisieren, Solawi, HoflÃ¤den, Fairteiler nutzen&amp;pflegen, nebenan.de, ...)</p>\n\n<p><strong>2 </strong><strong>Lokal (</strong>Petitionen unterschrieben,Vereine wie NaBu und BUND unterstÃ¼tzen, MÃ¼ll sammeln, GemeinschaftsgÃ¤rten, Ackerhelden, FlohmÃ¤rkte, Kleinanzeigen, Repair CafÃ©, Leihladen, BÃ¼rgerbeteiligung, ...)</p>\n\n<p><strong>3 Global </strong>(globale Organisationen wie Peta/ Greenpeace/ Amnesty/ sea-watch/ Oxfam oder Ãrzte ohne Grenzen, alternativer Tourismus, Ã¼ber den Tellerrand schauen, Crowdfunding, Tierretter, Petitinen unterschreiben, globale Ethik ausbilden wie Tich Nat Hahn sagte, ...)</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1759', '<p>das groÃe ganze z.b FIFA gekonzept</p>\n\n<p>Wald: Bedeutung von Wald in der frÃ¼heren Zeit</p>\n\n<p>Zweitens Vielfalt im Raum ins BÃ¼ro von waldgÃ¤rten sieben Schichten drei Ebenen mosaiksystem einzelne Mosaiken unterschiedlichen Stadien zeitlich obstbaum was ist Bernd was ist GemÃ¼se</p>\n\n\n\n<p>Drittens Vielfalt in der Jahreszeit:</p>\n\n<p>Ein immergrÃ¼nes Stilleben ist langweilig, hoch pflegeaufwendig und nicht lecker. Schaff Dir ein lebendiges, sich verÃ¤nderndes System! Startpunkt: Saisnaler Speiseplan. :)</p>\n\n<p>FrÃ¼hling: - BirkenblÃ¤ttersalat mit WildkrÃ¤utern und BÃ¤rlauchnockelrn</p>\n\n<p>Sommer: Beeren-Crumble-Kuchen im Garten essen</p>\n\n<p>Herbst: Stockbrot mit Quer-durchs-Garten-Pesto am Lagerfeuer naschen und Gartengeschichten erzÃ¤hlen</p>\n\n<p>Winter: Mini-Gartenauszeiten und GÃ¤nseblÃ¼mchengrÃ¼n nschen. Eingekochtes. Frische MÃ¶hren aus dem Hochbeet.</p>\n\n\n\n<p>Viertens Vielfalt in Form Farbe und Geschmack!</p>\n\n<p>Es gibt viel mehr, als wir im Baumarkt und Supermarkt entdecken kÃ¶nnen.</p>\n\n<p>LECKER!</p>\n\n<p>Bild Alles GemÃ¼se, oder was???</p>\n\n<p>Meine 3 Highlights: Tabelle</p>\n\n<p>5 vielfÃ¤ltige Ideen zur Umsetzung z.b Obst vom lebensgemeinschaft, naschwege, TeekrÃ¤uterbeet, essbares Spalier oder moderner Bauerngarten</p>\n\n<p>Check Waldgartenvortrag</p>\n\n<p>- alte resistente Sorten: Quitte</p>\n\n\n\n<p>Nacschen durch die Jahreszeiten</p>\n\n<p>interessant GeschmÃ¤cker</p>\n\n<p>Taglilein</p>\n\n<p>pendant z u bananaenblÃ¤ttern: Funkien</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1762', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1763', '<p><strong>Meine Ausbildung und berufliche Laufbahn umfassen:</strong></p>\n\n<ul>\n	<li>\n	<p>Fachabitur, Fachkrankenpflegerin fÃ¼r Onkologie und 10 Jahre Arbeit in diesem Bereich</p>\n	</li>\n	<li>\n	<p>Permakultur-Design-Kurs (2018) â <em>Seitdem Mitarbeit in verschiedenen Projekten, darunter ein 3-monatiges Projektmanagement auf Sri Lanka mit der Permakulturschule Ãsterreich.</em></p>\n	</li>\n	<li>\n	<p>Fachberaterin fÃ¼r Selbstversorgung mit essbaren Wildpflanzen (2019).</p>\n	</li>\n	<li>\n	<p>Permakultur-Ausbildung (2020-2025) an der deutschen Permakulturakademie</p>\n	</li>\n	<li>\n	<p>Diplomierte Permakultur-Gestalterin seit 2025</p>\n	</li>\n	<li>\n	<p>aktuelle Ausbildungen: Fernstudium der Gartenplanung und Ausbildung \"Inner Freedom Work\" (Permakultur des Herzens)<sup class=\"footnote\">1</sup></p>\n	</li>\n</ul>\n\n<p><strong>Berufserfahrung und Projekte:</strong></p>\n\n<ul>\n	<li>\n	<p>Facilitator in mehreren zweiwÃ¶chigen Permakultur-Designkursen (2020-2023).</p>\n	</li>\n	<li>\n	<p>DurchfÃ¼hrung von Permakultur-EinfÃ¼hrungskursen und Workshops zum GelÃ¤ndedesign.</p>\n	</li>\n	<li>\n	<p>Beratung und Planung von Lebensmittelkooperativen und mehreren SelbstversorgergÃ¤rten.</p>\n	</li>\n	<li>\n	<p>NÃ¼tzlingsbiotope im Hausgartenbereich und auf dem Ã¤ltesten Permakultur-GelÃ¤nde Europas (Choka Sangha e.V.).</p>\n	</li>\n	<li>\n	<p>Planung einer Solidarischen Landwirtschaft auf 1,5 ha (Greene).</p>\n	</li>\n	<li>\n	<p>Betreuung des Permakultur-Nord-Netzwerks und Mitarbeit am Permakultur-KÃ¼chen-Projekt.</p>\n	</li>\n</ul>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1764', '<p><strong>Vision</strong></p>\n\n<p>Meine Vision ist es, Verbindung und lÃ¶sungsorientiertes Denken wieder zu stÃ¤rken und in die Gesellschaft zu integrieren. Ich mÃ¶chte einen Raum schaffen, in dem wir uns als Menschen echt begegnen kÃ¶nnen, uns in unseren BedÃ¼rfnissen wahrnehmen und gemeinsam verantwortungsbewusst und authentisch leben.</p>\n\n<p>Die Zyklen des Lebens zu verstehen und natÃ¼rliche Rhythmen zu kultivieren, ist dabei ein zentraler Bestandteil meines Ansatzes. FÃ¼r mich bedeutet Permakultur nicht nur nachhaltige Garten- und<strong> </strong>Landschaftsgestaltung, sondern die Schaffung von heilungsfÃ¶rdernden Biotopen fÃ¼r Menschen und Natur. Ich mÃ¶chte, dass wir den Kreislauf als NormalitÃ¤t sehen â Abschiede ebenso feiern wie neue AnfÃ¤nge, und Reflexion und Integration als fortlaufende Prozesse begreifen.</p>\n\n<p>Durch meine Arbeit mÃ¶chte ich die vielfÃ¤ltigen Potenziale von Menschen, Gemeinschaften und Ãkosystemen sichtbar machen und sie mit nachhaltigen, kreativen LÃ¶sungen unterstÃ¼tzen. Gemeinsam wollen wir Wunder entdecken, die uns umgeben â von den kleinen Momenten bis zu den groÃen VerÃ¤nderungen. In meinen Permakultur-Prozessen unterstÃ¼tze ich Menschen dabei, ihre eigene KreativitÃ¤t und<strong> </strong>Wirksamkeit zu entfalten, um wirklich nachhaltige, an den Kontext angepasste Designs zu entwickeln.</p>\n\n<p><strong>Meine HerzenswÃ¼nsche:</strong></p>\n\n<ul>\n	<li>\n	<p>Mehr Verbindung zwischen Menschen und ihren natÃ¼rlichen LebensrÃ¤umen.</p>\n	</li>\n	<li>\n	<p>Fokus auf das Gemeinsame, auf das, was uns eint und uns voranbringt.</p>\n	</li>\n	<li>\n	<p>Kreislaufdenken als fundamentale Haltung zu kultivieren und VerÃ¤nderung als natÃ¼rlichen Teil unseres Lebens zu betrachten.</p>\n	</li>\n	<li>\n	<p>Unsere grÃ¼nen Oasen und heilsamen LebensrÃ¤ume zu genieÃen, mit einem GefÃ¼hl von Genuss und GenÃ¼gsamkeit.</p>\n	</li>\n</ul>\n\n<p><strong>Zitat von John Krabat Zinn</strong>: <em>âDie kleinen Dinge. Die kleinen Momente. Die sind nicht klein.â</em></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1765', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1768', '<p><strong>Permakultur erleben â lebendig, praxisnah und inspirierend.</strong><br />\nIch biete VortrÃ¤ge, Kurse und Workshops rund um Ã¶kologische Gestaltung, soziale Prozesse und zyklisches Denken. FÃ¼r alle, die Zukunft aktiv mitgestalten wollen.</p>\n\n<p>In meinen VortrÃ¤gen, Kursen und Workshops vermittle ich Permakultur als ganzheitlichen Gestaltungsansatz fÃ¼r GÃ¤rten, Landschaften, Gemeinschaften und innere Prozesse. Theorie und Praxis greifen ineinander â mit Raum fÃ¼r Fragen, Austausch und eigene Erfahrungen.</p>\n\n<p>Meine Veranstaltungen richten sich an:</p>\n\n<ul>\n	<li>\n	<p>junge Menschen, die Permakultur lernen und leben wollen</p>\n	</li>\n	<li>\n	<p>Initiativen, Projekte und Gruppen mit Ã¶kologischem oder sozialem Fokus</p>\n	</li>\n	<li>\n	<p>Menschen, die Zukunft bewusst, freudvoll und verantwortungsvoll gestalten mÃ¶chten</p>\n	</li>\n</ul>\n\n<p>Dabei verbinde ich <strong>grÃ¼ne, soziale und zyklische Permakultur</strong> â immer angepasst an den jeweiligen Kontext und die Menschen vor Ort.</p>\n\n<p>MÃ¶gliche Themenbereiche:</p>\n\n<p>Permakultur EinfÃ¼hrung, Workshop Gartengestaltung, Alegen einer essbaren Landschaft, Zyklische Permakultur, ...</p>', '');
