INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1773', '<p>Als diplomierte Permakultur-Designerin begleite ich Menschen, Gruppen und Projekte dabei, <strong>zukunftsfÃ¤hige LebensrÃ¤ume</strong> zu gestalten â vom Kleingarten Ã¼ber Gemeinschaftsprojekte bis hin zu Ã¶ffentlichen RÃ¤umen.</p>\n\n<p>     Ã¶kologisch â¢ gemeinschaftlich â¢ prozessorientiert</p>\n\n<p>ich finde gemeinsam mit Euch und einem Permakulturprozess ein wirklich nachhaltiges Design angepasst auf den jeweiligen Kontext.</p>\n\n<p>FÃ¼r eine persÃ¶nliche Beratung habe ich ein niedrigschwelliges Angebotspaket geschnÃ¼rt â online â Kurzberatung. Siehe Link am Ende der Seite.</p>\n\n<p>FÃ¼r eine weitergehende, umfassendere Begleitung vor Ort kannst Du mich auf Stundenbasis buchen. Ich freue mich auf deien Anfrage!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1774', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1777', '<p>Die Welt ist voller MÃ¶glichkeiten! Mit meiner Arbeit mÃ¶chte ich diese vielfÃ¤ltigen Potenziale von Menschen, Gemeinschaften und Ãkosystemen sichtbar machen &amp; nutzen.</p>\n\n<p>Um die Welt von morgen bewusst im Hier und Jetzt gestalten zu kÃ¶nnen lass dich inspirieren:</p>\n\n<p>- Blog</p>\n\n<p>- Sprechstunde</p>\n\n<p>- Werkzeugpalette</p>\n\n<p>- Wissenspakete</p>', '');
