INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1796', '<p>zum Beispiel durch:</p>\n\n<ul>\n	<li>\n	<p>Humusaufbau und Bodenpflege: #Mulch-Liebe, Kreislaufwirtschaft, RegenwÃ¼rmer fÃ¼ttern, GrÃ¼ndÃ¼ngung, ...</p>\n	</li>\n	<li>\n	<p>Vielfalt im naturnahen Garten fÃ¶rdern: Obstbaumgilde, essbarer Waldgarten, Kleinstbiotope, Wildtierhabitaten und seltenen heimischen Pflanzen</p>\n	</li>\n	<li>\n	<p>Ressourcenbewusstsein und KreislÃ¤ufe schlieÃen</p>\n	</li>\n</ul>', '');
