INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1798', '<p>zum Beispiel durch:</p>\n\n<ul>\n	<li>\n	<p>Selbstliebe pflegen -&gt; mit gutem Essen, Auszeiten und bewussten Ritualen</p>\n	</li>\n	<li>\n	<p>Menschen offen begegnen: Was bewegt dich gerade, wie geht es Dir?</p>\n	</li>\n	<li>\n	<p>Ehrliches Mitteilen und zuhÃ¶ren in geschÃ¼tzten RÃ¤umen, z.B. im Redekreis. Frieden stiften in deinem Einflussfeld</p>\n	</li>\n</ul>', '');
