INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1802', '<p>Zum Beispiel durch:</p>\n\n<ul>\n	<li>\n	<p>Ein empathisches LÃ¤cheln mit Mitmenschen teilen</p>\n	</li>\n	<li>\n	<p>Wissen teilen, Saatgut &amp; ErnteÃ¼berschÃ¼sse, gemeinsam Projekte umsetzen fÃ¼r Inspiration, Austausch und UnterstÃ¼tzung</p>\n	</li>\n	<li>\n	<p>Commons (-gedanken) fÃ¶rdern, gemeinwohlorientiertes Handeln</p>\n	</li>\n</ul>', '');
