INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1811', '<p>Wenn ich mal wieder nicht weiÃ: âWas ist der nÃ¤chste Schritt?â, helfen mir diese LeitfÃ¤den dranzubleiben, Klarheit zu schaffen und Entscheidungen zu treffen.</p>\n\n<p>DarÃ¼ber hinaus macht es Sinn, Stufe fÃ¼r Stufe ein ganzheitliches Design zu entwickeln.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1812', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1813', '<p>GrundsÃ¤tze: Beobachte mÃ¶glichst neutral. Was kannst Du mit all deinen Sinnen erfassen und mÃ¶glichst neutral beschreiben?</p>\n\n<p>Nicht Ã¤rgern, wenn Du den dornigen Busch mit weiÃen BlÃ¼ten im MÃ¤rz nicht identifizieren kannst. Merk Dir den Standort und beobachte das GehÃ¶lz weiter im Verlauf des Jahres. So kannst Du dich bekannt machen mit der Schlehe! Um echtes Wissen zu generieren ist mein Grundsatz: Eher wundern als feststellen.</p>', '');
