INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1815', '<p>Meine Beobachtung schulte sich zu Beginn mit Wildpflanzen. Vor 5 Jahren begann ich auf den Boden zu schauen! Mittlerweile nasche ich mich so gesund und abwechslungsreich durch den Garten.</p>\n\n<p>Denn die kleinen Dinge im Leben, die sind nicht klein.</p>', '');
