INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1826', '<p>Ist eine differenzierte Analyse eines einzelnen Elements.</p>\n\n<p>Was geht \"rein\", was geht \"raus\"? Welches BedÃ¼rfnis hat dieses Element? Was erfÃ¼llt dieses Element in meinem System und welche VerknÃ¼pfungen gibt es?</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1827', '', '');
