INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1831', '<p>Die Analyse dieser drei Aspekte ist Richtungsweisend fÃ¼r eine nachhaltige Gestaltung. Setze dich intensiv damit auseinander, alle Beteiligten und Elemente des Systems betreffend.</p>\n\n<p>Soziales Beispiel: Analyse fÃ¼r die Absprachen in einem Arbeitsteam</p>\n\n<p><strong>1 Ressourcen:</strong><strong> </strong>Bereitschaft, ein fester Tag in der Woche, gemeinsame Mahlzeiten, Redestab, gemeinsame Pausen.</p>\n\n<p><strong>2 </strong><strong>BedÃ¼rfnisse: â</strong>gesehen werdenâ, privater Austausch (wie geht es mir gerade &amp; was bewegt mich), Klarheit in der Entscheidungsfindung: z.b Konsens oder Soziokratie.</p>\n\n<p><strong>3 Begrenzung: </strong>z.B. maximal eine gemeinsame ruhige Stunde, mÃ¶gliche Konflikte die mehr Raum brauchen., schlechte RaumverhÃ¤ltnisse: nicht alle sehen sich gut.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1832', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1833', '<p>Maja GÃ¶pel beschreibt in ihrem Buch âWerte. Ein Kompass fÃ¼r die Zukunftâ<sup class=\"footnote\">1</sup> eine Art des fÃ¼rsorglichen Designens<sup class=\"footnote\">2</sup>.</p>\n\n<p>Die Gruppe Architects for Future formulierte dazu 3 GrundsÃ¤tze:</p>\n\n<p>- fuÃt auf naturpositiven LÃ¶sungen,</p>\n\n<p>- Multi-Gewinn-Strategie (=Win-Win-Situationen)</p>\n\n<p>- und modularen Konzepte.</p>\n\n<blockquote>\n<p><strong>Ein Haus muss eine lebendige, organische Einheit sein, die sich fortentwickelt und sich stÃ¤ndig wandelt. Hundertwasser</strong></p>\n</blockquote>', '');
