INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1836', '<p>Pflege-Nutzen ist eine innere Haltung, die wir wieder entwickeln dÃ¼rfen. Wie behandle ich meine Sachen, die Erde und Mitmenschen mÃ¶glichst schonend? Spurlosigkeit Ã¼ben und doch meinen individuellen Abdruck hinterlassen auf dem Trampelpfad, den ich tÃ¤glich benutze. Bewusst achtsam mit Liebe!</p>\n\n<p>Prof. Dr. Maja GÃ¶pel:</p>\n\n<blockquote>\n<p>Jede VerÃ¤nderung die wir heute vornehmen wird ein Teil zukÃ¼nftiger Entwicklung sein.</p>\n</blockquote>', '');
