INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1850', '<p>Ich persÃ¶nlich empfehle zuerst das tiefe Beobachten: deiner inneren Natur &amp; Rhythmus, sowie dem AuÃen.</p>\n\n<p>UND Waldbaden tut bekanntermaÃen gut â mit frischer Luft fÃ¼r klare Gedanken.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1851', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1852', '<p><strong>Planen fÃ¼r Extreme:</strong></p>\n\n<p>Sri Lanka, 2019: Ein zerstÃ¶rter Wassercontainer, von einem wutentbrannnten Elefanten zertrampelt. Immer merh aggressive Verhaltensweisen treten auf, die DickhÃ¤uter reiÃen ZÃ¤une nierder, vernichten ernte und manchmal fÃ¼rht das zu tÃ¶dlichen ZwischenfÃ¤llen fÃ¼r Menschen. In dem Projekt, bei dem ich mitarbeiten durfte, lernten wir Strategien zur Verteidugung: tiefe GrÃ¤ben, Rauchbomben aus getrockneten Chillis und Dung oder mit Bienen desigenn (Elefanten mÃ¶gen keine Bienen). Doch was liegt dem zugrunde? Sri Lanka ist eien verhÃ¤ltnismÃ¤Ãig kleine Insel und den Elefanten bleibt immer weniger Raum und Nahrung Ã¼brig. Sie handeln aus purem Ãberlebensinstinkt. Mein Fazit: Alles ist verbunden und bedingt einander.: Nur wenn wir wirklich bewusst handeln und uns der Konsequenzen jeder einzelnen Person und VerÃ¤nderung bewusst sind, kÃ¶nnen wir nachhaltig und resilient gestalten. Wir haben es buchstÃ¤blich in der Hand. Kontext: Elefantengeschichte</p>\n\n<p>Plane mit der Klarheit: Alles ist VerÃ¤nderung! Das gibt Gelassenheit und die MÃ¶glichkeit der Sukzessionplanung.</p>', '');
