INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1862', '<p>Es ist MÃ¤rz, die Sonne strahlt und es juckt Dir unter den FingernÃ¤geln, die Beete abzurÃ¤umen und ins neue Gartenjahr zu starten. Atme durch, deine Zeit wird kommen. Wenn Du diese Ambivalenz bis Mai hinnimmst und die Nachwuchs-Insekten und Baby-Tiere in Ruhe lÃ¤sst, wirst Du mit wahrscheinlich vielen Schmetterlingen im Sommer belohnt werden. Jedes Jahr mehr!</p>\n\n<p>Schreib deine \"Not to Do Liste\" fÃ¼r den Naturgarten.</p>', '');
