INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1864', '<p>Wusstest Du, dass das Microbiom unserer beiden HÃ¤nde bis zu 10 Millionen Bakterien - 5000 Arten umfasst? Und, geradezu unfassbar nur zu 17% identisch ist?</p>\n\n<p>Das bedeutet einen Unterschied von unglaublichen 83% zwischen deiner rechten und linken Hand!</p>\n\n<p>Hand reichen: Austausch.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1866', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1867', '<p>Im Permakultur Design werden regelmÃ¤Ãig solche Muster genutzt, die meherere unterschiedliche Zonen und Strukturen schaffen. Dadurch bilden sich ein Mikroklima-Mosaik fÃ¼r die DiversitÃ¤t, besispielsweise mit einer Sonnenfalle oder einem HÃ¼gelbeet</p>\n\n<p>In der Natur, bei Tieren und Pflanzen ist es wie bei Menschen: Manch einer mag in der prallen Sonne sitzen, manch einer kann das gar nicht. Holmgren-Prinzip No.10: Nutze und schÃ¤tze die Vielfalt.</p>\n\n<p>Ein Ãbergang = Schwelle. ZustandsverÃ¤nderung im Prozess der Entwicklung: manchmal impulshaft, schnell und plÃ¶tzlich. Oft schleichend und sich ankÃ¼ndigend.</p>\n\n<p>SchÃ¤tze das Marginale!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1868', '', '');
