INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1923', '<p>Gartenaffine Mensch wissen aus Erfahrung: Jedes Gartenjahr ist anders! Alles ist einzigartig, jeder Moment, in dem Elemente auf der Erde aufeinandertreffen und miteinander interagieren.</p>\n\n<p>Besonders unter freiem Himmel, im Garten, Wegesrand und Wald kannst Du die naturalistischen Reihenfolgen direkt erfahren und Dich erden im Strudel der Lebendigkeit â nur eben ganz langsam.</p>\n\n<p>Plopp â das Blatt fÃ¤llt auf den Boden.</p>\n\n<p><em>Eins ist gewiss: alles ist vernetzt.</em></p>', '');
