INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1931', '<p>FÃ¼r mich ist saisonales Leben eine Bereicherung meines Lebens: das Auskosten von FÃ¼lle &amp; Dankbarkeit Ã¼ber PhasenÃ¼bergÃ¤nge und natÃ¼rliche Begrenzung. Stell Dir vor, die Zucchinischwemme wÃ¼rde nie enden? Oder Du wÃ¤rst jede Sekunde deines Lebens einfach nur maximal glÃ¼cklich? SaisonalitÃ¤t lÃ¤dt uns ein, tiefe WertschÃ¤tzung fÃ¼r die leckere Abwechslung des Lebens in seiner Ambivalenz zu entwickeln!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1932', '<p>In der LandschaftsÃ¶kologie beschreibt eine Sukzession die natÃ¼rliche Entwicklung einer FlÃ¤che ohne Eingriff durch Menschen. NatÃ¼rlicherweise wÃ¼rde ein Rasen langsam aber sicher von Pioneer-GewÃ¤chsen (z.B. Brombeeren) Ã¼berwachsen werden und in einigen Jahren zu Wald. Dieses PhÃ¤nomen denken und designen wir mit</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1933', '<p>ist ein Merkmal der natÃ¼rlichen Entwicklung in StoffkreislÃ¤ufen auf der Erde. Die Entropie, also die Unordnung nimmt zu, wenn Stoffe vermischt werden oder Energie âverlorenâ geht<sup class=\"footnote\">1</sup>. Auf der Erde ist die und begrenzt Ordnung schaffende Energie theoretisch unsere Sonnenenergie. Das steht der Entropie der Erde entgegen. Nichts ist von langer Dauer!</p>', '');
