INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1946', '<p>Entwicklung ist ein Hauptcharakteristikum im Prozess! Das Leben kann nicht rÃ¼ckwÃ¤rts gelebt werden, wie in dem Film Benjamin Button. Gleichzeitig ist auf diesem Planeten alles prozesshaft. Es hat seine eigenen, natÃ¼rlichen GesetzmÃ¤Ãigkeiten, Abfolgen und Synergien.Unser Lebenslauf, die Jahreszeiten, die Entwicklung einer TropfsteinhÃ¶hle. Alles ist VerÃ¤nderung, nichts hat Bestand. Das Leben entfaltet sich Schritt fÃ¼r Schritt im Prozess.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1947', '<p>Stetigkeit ist fÃ¼r mich Ganzheit im Prozess. Von Zeit zu Zeit Ã¤rgere ich mich, in der KÃ¼che stehend, Ã¼ber die Endlosigkeit der Geschehnisse. Gerade ist die ArbeitsflÃ¤che sauber und das Geschirr abgespÃ¼lt â schon geht das kochen von vorne los. Doch genau das ist Lebendigkeit! Zum kochen und essen gehÃ¶rt auch die Nachbereitung der KÃ¼che in Dankbarkeit.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1948', '<p>...wird oft strategisch in der Permakultur-Gestaltung genutzt. Eine detaillierte Planung basiert auf saisonalen Faktoren und natÃ¼rlichen Rhythmen, die in der Umsetzung logisch und langsam genutzt werden. Eine solche Nutzung von Nischen in der Zeit findest Du z.B. bei HÃ¼gelbeeten.</p>', '');
