INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1950', '<p>Was in Windeseile Ã¼ber Nacht entsteht hat oft keine Standfestigkeit, Nachhaltigkeit oder ist von Dauer. Lass Dir Zeit fÃ¼r Entwicklung und nimm Dir ein Beispiel an einem stabilen Ãkosystem wie einem ausgewachsenen Wald.</p>\n\n\n\n<p>Im Prozess zu leben schenkt uns die Notwendigkeit, zurÃ¼ckzutreten von âwas wir wollenâ und stattdessen in die tiefe Beobachtung einzutauchen. Brauche ich gerade eine Vision oder Idee? Orientierung? Klarheit durch Reflexion? Struktur im Tun oder etwas Pause zur Regeneration?</p>\n\n<p>Deswegen ist Permakultur die permanenete Impermanenz!</p>\n\n<h6>Und: das Leben ist kein Wettrennen bis zum Schluss.</h6>', '');
