INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1953', '<p>In deinem ureigenen zyklischen Tempo zu leben, ist eine Rebellion gegen die dauerhaften Stromschnellen der Gegenwart im AnthropozÃ¤n. Das FluÃbett deines Lebens darf natÃ¼rlich und vielfÃ¤ltig sein. DarÃ¼ber hinaus: mÃ¤andern zwischen HÃ¤ufung und Erosion.</p>\n\n<p><strong>Finde deine Einzigartigkeit!</strong></p>', '');
