INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1964', '<p>Diese Prozessphase steht fÃ¼r den Fokus und die Struktur. Bis vor kurzem dachte ich noch, das impliziert auch Anstrengung! TatsÃ¤chlich ist die Hauptsache: einfach tun und die bereits investierte Energie in die Vision flieÃen lassen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1965', '<p>Nach dem Fokus kommt die Ruhe, z.B. bei einer Siesta. Wellness, fÃ¼r uns sorgen.</p>\n\n<p>Hiermit lade ich ein, zum richtigen Zeitpunkt, in der richtigen Dosierung und bewusst zelebriert: GEMÃÃÃTLICHKEIT!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('1966', '<p>Der Nordwesten lÃ¤dt uns ein, nicht an den VerÃ¤nderungen des Lebens zu zerschellen, sondern Resilienz auszubilden. Um flexibel zu bleiben ist es wichtig, mit offenen Augen zu sehen und zu verÃ¤ndern, was wir Ã¤ndern kÃ¶nnen. DafÃ¼r nutzen wir die Reflexion um mÃ¶glichst ehrlich zu betrachten und mit den reellen Bedingungen wachsen zu kÃ¶nnen.</p>', '');
