INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2008', '<p>in mein Leben einladen. DafÃ¼r bewege ich mich bewusst und beobachtend. Raus aus: âhÃ¶her - weiter - schnellerâ. Ich erlebe KlimaglÃ¼ck in der Entschleunigung<sup class=\"footnote\">1</sup>.</p>\n\n<p>Was bedeutet Freiheit? Ein Teil der Antwort ist fÃ¼r mich: einfach mit HÃ¤ngematte, Schlafsack &amp; Wanderschuhen in den Zug steigen zu kÃ¶nnen. Microabenteuer sind auch eine tolle Alternative zu einer ganzen Woche unterwegs sein!</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2009', '<p>Oft nehme ich kleine Umwege, um Erfahrungen einzuladen. Das frischt mein Gehirn auf und ich kann wieder phantasieren: wie kÃ¶nnen in VorgÃ¤rten, entlang Fahrradwegen und auf GrundstÃ¼cken essbare, artenreiche Paradiese entstehen? Wenn ich mit der Bahn durch Landschaften fahre sehe ich Potenziale und MÃ¶glichkeiten die zur regenerativen Zukunft fÃ¼hren.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2010', '<p>TÃ¤glich fahre ich mit Freude Fahrrad<sup class=\"footnote\">2</sup>. Diese MobilitÃ¤tsform ist einfach praktisch, weil die Parkplatzsuche wegfÃ¤llt und flexibel, wie mein Leben<sup class=\"footnote\">3</sup>. Letztes Jahr entdeckte ich auch meine Liebe zu Fahrrad-Reisen, die perfekte Kombination aus entschleunigtem Low-Budget-Reisen und groÃem Radius<sup class=\"footnote\">4</sup>. Andere MÃ¶glichkeiten sind Car-Sharing, MitfahrbÃ¶rsen und auch trampen ist meiner Erfahrung nach eine abenteuerliche und sehr lohnenswerte Bewegungsform.</p>\n\n<p>Ich unterstÃ¼tze inklusive RÃ¤ume, denn sie sind wichtig in jeder Hinsicht!<sup class=\"footnote\">5</sup></p>\n\n<p>Langsam und bewusst spazieren zu gehen lÃ¤sst mich in die Stimmung meiner Umgebung eintauchen, am liebsten in Kombination mit dem Ausschau halten nach essbaren Wildpflanzen und Pilzen. Manchmal nehme ich mir einfach vor, laufen zu gehen und offen zu sein fÃ¼r das, was sich zeigt.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2011', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2012', '<p>Deinen inneren Kompass auf âResetâ zu stellen, Resilienz auszubilden und neue Perspektiven zu gewinnen â durch eine bewusste Kombination aus Entschleunigung und bewusster MobilitÃ¤t.</p>\n\n<h6>Sei Fair unterwegs, mit Dir, der Erde und teilend.</h6>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2013', '', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2014', '<p><strong>Rituale </strong><strong>zelebrieren </strong></p>\n\n<p>Mit bewussten Ritualen wÃ¼rdige ich meine Zeit und gebe den Dingen darin Bedeutung statt sie wie eine Maschiene abzuarbeiten.</p>\n\n<p>Meine wichtigsten Rituale im Alltag sind:</p>\n\n<ul>\n	<li>âguter Start in den Tagâ zelebrieren.</li>\n	<li>einmal am Tag rausgehen, verbinden. Mond-, Sonne-, Erde-, Pflanzen-, Insekten-, Wald-, Pilz-, oder Vogel-TV gucken.</li>\n	<li>tÃ¤glich die wichtigsten Erlebnisse aufschrieben. Das mache ich in meinem Bullet Journal, 2 SÃ¤tze Dankbarkeit gegenÃ¼ber der FÃ¼lle, als mein âguter Abschlussâ des Tages.</li>\n</ul>\n\n<p>Weitere Inspirationen: Ruhige Nachmittagsstunde mit GemÃ¼Ã¼Ã¼Ã¼tlichkeit. Mir selbst vorlesen am Abend. AromaÃ¶le oder anderen Reize nutzen: basale Stimulation, AtmosphÃ¤re schaffen.</p>\n\n<p><strong>Pflegen &amp; WertschÃ¤tzen:</strong> Pflege ist ein Ritual der WÃ¼rdigung. Ich lerne so langsam, was âPflegenutzenâ bedeutet. Mittlerweile habe ich tatsÃ¤chlich gute Second-Hand- und Funktions-Kleidung, die mir passt. Nach dem Experiment mit 3 Jahre lang konsequent gar keine Kleisung zu kaufen, fÃ¼hlte ich mich nicht mehr wohl in unpassender synthetischer Kleidung. Ich beschÃ¤ftige mich mittlerweile viel mehr mit der Frage: wie kann ich die Lebensdauer meiner Kleidung qualitativ verlÃ¤ngern? Das gilt natÃ¼rlich auch fÃ¼r den KÃ¶rper und viele andere Bereiche.</p>\n\n<p>Mini - Impulse: Alltagsgegenstand ganz neu und innig betrachten<sup class=\"footnote\">1</sup>. Platz schaffen, regelmÃ¤Ãig.</p>\n\n<h6>John Kabat Zinn: \"Die kleinen Dinge. Die kleinen Momente. Die sind nicht klein.â</h6>', '');
