INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2026', '<p>GemeinwohlÃ¶konomie, Fab Labs, offene WerkstÃ¤tten Einkaufsgemeinschaften, ethische JobbÃ¶rsen, Energiegenossenschaften, BÃ¼rgergesellschaft, Anstiftung, SaatguttauschbÃ¶rsen, ...</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2027', '<p>Commons, Mietshaussyndikat, gemeinsame Ãkonomie bewusst gestalten, Food Sharing, Verpackung neu denken, Plastik reduuzieren, Seed Library Network, Regiogeld, DiDay, Mein BGE,â¦.</p>', '');
