INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2050', '<p>Du bist nicht mehr dieselbe Person wie zu Kindertagen. Du entwickelst Dich und hast das Potenzial, dein Leben aktiv zu gestalten nach deinen BedÃ¼rfnissen. Was ich persÃ¶nlich am meisten mag: wenn ich mich hin und wieder selbst Ã¼berraschen kann. :)</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2051', '<p>Entwickle behutsam MitgefÃ¼hl mit Dir und Anderen. Raum nehmen um zu verdauen, z.B. in der Meditation oder mit psychologischer UnterstÃ¼tzung: âIch gehe meine GefÃ¼hle fÃ¼hlen.â</p>\n\n<p>MÃ¶gliche Werkzeuge: GefÃ¼hlskompass (Vivian Dittmar)<sup class=\"footnote\">2</sup>, BedÃ¼rfnissprache<sup class=\"footnote\">3</sup>, Inner Freedom Work<sup class=\"footnote\">4</sup></p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2052', '<p>Kreislaufprinzip<strong> </strong>anwenden: bewusstwerden von nicht-heilsamen Strategien und ausprobieren von Alternativen.</p>\n\n<p>Ein Beispiel: Jeden Tag im Stadtverkehr im Auto brÃ¼llen bringt mich nicht weiter, nur einen Herzinfarkt nÃ¤her. MÃ¶gliche LÃ¶sungswege: Stressball oder Akkupressurring verwenden, die Fahrt nutzen um mich weiterzubilden, Radical Honesty Ã¼ben wenn es der richtige Rahmen ist- Fenster runterlassen und Klarheit schaffen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2053', '<p>HÃ¶r auf dein BauchgefÃ¼hl und handle lÃ¶sungsorientiert. Wenn sich etwas nicht stimmig anfÃ¼hlt, forsche weiter. Um genÃ¼gend KapazitÃ¤ten dafÃ¼r zu haben, kannst Du auf unterschiedlichen Wegen Psychologisches Kapital entwickeln (Hoffnung, Selbstwirksamkeit, Resilienz, Optimismus).</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2054', '<p>Meinen inneren Kompass mÃ¶chte ich mindestens einmal am Tag in eine Neutral-Stellung bringen, und mich dabei zu zentrieren. Bei mir persÃ¶nlich funktioniert der Kompass-Reset wunderbar beim Schwimmen, Meditieren, Kochen, Singen, Eisbaden, Saunieren, oder einem Kakaoritual.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2055', '<p>Wir kÃ¶nnen jederzeit Ã¼ben, die Geschenke des Lebens dankbar wertzuschÃ¤tzen und anzunehmen. Zyklisch leben kann dazu beitragen eine kulturelle Praxis der Dankbarkeit zu etablieren. Danke den Elementen, ZufÃ¤llen und Geschenken, die tÃ¤glich in dein Leben kommen. Nichts ist selbstverstÃ¤ndlich innerhalb unserer Lebenszeit.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2056', '<p>âNichts wird so oft unwiederbringlich versÃ¤umt wie eine Gelegenheit, die sich tÃ¤glich bietet.â</p>\n\n<p>(Marie von Ebner-Eschenbach)</p>', '');
