INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2068', '<p>Es ist die Abstimmung darÃ¼ber, wie kommuniziert und gehandelt wird. Klare gemeinsame Kommunikationsgrundlagen wie ein Zebrastreifen auf der StraÃe, verhindern UnfÃ¤lle, MissverstÃ¤ndnisse und Leid . DarÃ¼ber hinaus ist Transparenz entscheidend. Zum einen der RealitÃ¤tsabgleich: Ã¼ber was sprechen wir eigentlich gerade? Wenn Menschen Ã¼ber BÃ¤ume sprechen hat oft jede Person ein ganz anderes Bild im Kopf. Und zum anderen Transparenz in Entscheidungen und Handlungen.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2069', '<p>FÃ¼r ein ruhiges GesprÃ¤ch auf AugenhÃ¶he mag ich mich selbst im flieÃenden Alltag mag ich mich gemeinsam hinsetzen. So fÃ¤llt es mir leichter, auf die Herzebene zu kommen und echtes zuhÃ¶ren zu Ã¼ben. Klarheit schaffen: Was ist das hier gerade fÃ¼r ein Raum?</p>\n\n<p>LÃ¶sungsorientierte Kommunikation kann durch Visualisierungen (z.B. Skalen) unterstÃ¼tzt werden.</p>\n\n<p>Ein mit Herz geÃ¶ffneter GesprÃ¤chsraum kann auch so geschlossen werden: durch eine differenzierte, wertschÃ¤tzende Feedbackkultur.</p>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2070', '<p>Ein vetrauensvoller, klarer gestalteter Raum entsteht gemeinsam, entwickelt sich mit der Zeit und bietet viel Platz. Wenn ich im nÃ¤chsten Schritt jeder seine BedÃ¼rfnisse Ã¤uÃert, kann gemeinsamer Humus gebildet werden zu einem zusammenleben auf Vertrauensbasis. Damit kÃ¶nnen auch Krisen und Konflikte leichter verdaut werden.</p>\n\n<h6>Im Alltag geht es oft um die Kleinigkeiten, die einen echten Unterschied im Miteinander machen.</h6>', '');
INSERT INTO `field_text` (`pages_id`, `data`, `data1025`) VALUES('2071', '', '');
