INSERT INTO `fieldgroups_fields` (`fieldgroups_id`, `fields_id`, `sort`, `data`) VALUES('109', '137', '1', '{\"description\":\"Zus\\u00e4tzliche l\\u00e4ngere Beschreibung (optional), falls die Beschreibung (alt-text) nicht reicht. Besonders n\\u00fctzlich f\\u00fcr Diagramme, Infografiken oder Kunstwerke. Nicht auf der Webseite sichtbar.\",\"notes\":\"Bsp: \\\"Das Diagramm visualisiert die Niederschlagsmenge im Jahr 2025 in Deutschland mit einer Balkengrafik. Es zeigt ein Koordinatensystem, welches auf der x-Achse die Monate des Jahres und auf der y-Achse die Niederschlagsmenge anzeigt. Es ist zu sehen, dass die Niederschlagsmenge in den Wintermonaten am h\\u00f6chsten ist.\\\"\"}');
