er a Github event called repository_dispatch.\",\"href\":\"https:\\/\\/docs.github.com\\/en\\/rest\\/repos\\/repos#create-a-repository-dispatch-event\",\"requiresVersions\":{\"PHP\":[\">=\",\"7.2.0\"],\"ProcessWire\":[\">=\",\"3.0.123\"]},\"installs\":[\"LazyCron\"],\"autoload\":true,\"singular\":true,\"created\":1765475399,\"installed\":false,\"configurable\":\"GithubRepositoryDispatch.config.php\"},\"AppApi\":{\"name\":\"AppApi\",\"title\":\"AppApi\",\"version\":\"1.3.2\",\"versionStr\":\"1.3.2\",\"author\":\"Sebastian Schendel\",\"summary\":\"Module to create a REST API with ProcessWire\",\"href\":\"https:\\/\\/modules.processwire.com\\/modules\\/app-api\\/\",\"icon\":\"terminal\",\"requiresVersions\":{\"PHP\":[\">=\",\"7.2.0\"],\"ProcessWire\":[\">=\",\"3.0.98\"]},\"permissions\":{\"appapi_manage_applications\":\"Manage AppApi settings\"},\"autoload\":true,\"singular\":true,\"created\":1735122024,\"installed\":false,\"configurable\":\"AppApi.config.php\",\"page\":{\"name\":\"appapi\",\"parent\":\"setup\",\"title\":\"AppApi\",\"icon\":\"terminal\"}},\"PagesVersions\":{\"name\":\"PagesVersions\",\"title\":\"Pages Versions\",\"version\":2,\"versionStr\":\"0.0.2\",\"author\":\"Ryan Cramer\",\"summary\":\"Provides a version control API for pages in ProcessWire.\",\"icon\":\"code-fork\",\"autoload\":true,\"singular\":true,\"created\":1767884980,\"installed\":false,\"core\":true}}', '2024-04-28 16:28:31');
